// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Login
	// (POST /auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Logout
	// (POST /auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Initiate OAuth flow
	// (GET /auth/oauth/{provider})
	OauthRedirect(ctx context.Context, request OauthRedirectRequestObject) (OauthRedirectResponseObject, error)
	// OAuth callback
	// (GET /auth/oauth/{provider}/callback)
	OauthCallback(ctx context.Context, request OauthCallbackRequestObject) (OauthCallbackResponseObject, error)
	// OAuth token exchange (SPA)
	// (POST /auth/oauth/{provider}/token)
	OauthTokenExchange(ctx context.Context, request OauthTokenExchangeRequestObject) (OauthTokenExchangeResponseObject, error)
	// Refresh access token
	// (POST /auth/refresh)
	RefreshToken(ctx context.Context, request RefreshTokenRequestObject) (RefreshTokenResponseObject, error)
	// Register a new user
	// (POST /auth/register)
	Register(ctx context.Context, request RegisterRequestObject) (RegisterResponseObject, error)
	// Request password reset
	// (POST /auth/self/forgot-password)
	ForgotPassword(ctx context.Context, request ForgotPasswordRequestObject) (ForgotPasswordResponseObject, error)
	// Self-register a new account
	// (POST /auth/self/register)
	SelfRegister(ctx context.Context, request SelfRegisterRequestObject) (SelfRegisterResponseObject, error)
	// Resend verification email
	// (POST /auth/self/resend-verification)
	ResendVerification(ctx context.Context, request ResendVerificationRequestObject) (ResendVerificationResponseObject, error)
	// Reset password
	// (POST /auth/self/reset-password)
	ResetPassword(ctx context.Context, request ResetPasswordRequestObject) (ResetPasswordResponseObject, error)
	// Verify email address
	// (POST /auth/self/verify-email)
	VerifyEmail(ctx context.Context, request VerifyEmailRequestObject) (VerifyEmailResponseObject, error)
	// List cities
	// (GET /cities)
	ListCities(ctx context.Context, request ListCitiesRequestObject) (ListCitiesResponseObject, error)
	// Create city
	// (POST /cities)
	CreateCity(ctx context.Context, request CreateCityRequestObject) (CreateCityResponseObject, error)
	// Delete city
	// (DELETE /cities/{id})
	DeleteCity(ctx context.Context, request DeleteCityRequestObject) (DeleteCityResponseObject, error)
	// Get city by ID
	// (GET /cities/{id})
	GetCity(ctx context.Context, request GetCityRequestObject) (GetCityResponseObject, error)
	// Update city
	// (PUT /cities/{id})
	UpdateCity(ctx context.Context, request UpdateCityRequestObject) (UpdateCityResponseObject, error)
	// List countries
	// (GET /countries)
	ListCountries(ctx context.Context, request ListCountriesRequestObject) (ListCountriesResponseObject, error)
	// Create country
	// (POST /countries)
	CreateCountry(ctx context.Context, request CreateCountryRequestObject) (CreateCountryResponseObject, error)
	// List cities by country
	// (GET /countries/{countryId}/cities)
	ListCitiesByCountry(ctx context.Context, request ListCitiesByCountryRequestObject) (ListCitiesByCountryResponseObject, error)
	// Delete country
	// (DELETE /countries/{id})
	DeleteCountry(ctx context.Context, request DeleteCountryRequestObject) (DeleteCountryResponseObject, error)
	// Get country by ID
	// (GET /countries/{id})
	GetCountry(ctx context.Context, request GetCountryRequestObject) (GetCountryResponseObject, error)
	// Update country
	// (PUT /countries/{id})
	UpdateCountry(ctx context.Context, request UpdateCountryRequestObject) (UpdateCountryResponseObject, error)
	// List documents
	// (GET /documents)
	ListDocuments(ctx context.Context, request ListDocumentsRequestObject) (ListDocumentsResponseObject, error)
	// Create document
	// (POST /documents)
	CreateDocument(ctx context.Context, request CreateDocumentRequestObject) (CreateDocumentResponseObject, error)
	// Delete document
	// (DELETE /documents/{id})
	DeleteDocument(ctx context.Context, request DeleteDocumentRequestObject) (DeleteDocumentResponseObject, error)
	// Get document by ID
	// (GET /documents/{id})
	GetDocument(ctx context.Context, request GetDocumentRequestObject) (GetDocumentResponseObject, error)
	// Update document
	// (PUT /documents/{id})
	UpdateDocument(ctx context.Context, request UpdateDocumentRequestObject) (UpdateDocumentResponseObject, error)
	// Add item to document
	// (POST /documents/{id}/items)
	AddDocumentItem(ctx context.Context, request AddDocumentItemRequestObject) (AddDocumentItemResponseObject, error)
	// Remove item from document
	// (DELETE /documents/{id}/items/{itemId})
	DeleteDocumentItem(ctx context.Context, request DeleteDocumentItemRequestObject) (DeleteDocumentItemResponseObject, error)
	// Update document item
	// (PUT /documents/{id}/items/{itemId})
	UpdateDocumentItem(ctx context.Context, request UpdateDocumentItemRequestObject) (UpdateDocumentItemResponseObject, error)
	// Combined health check
	// (GET /health)
	HealthCheck(ctx context.Context, request HealthCheckRequestObject) (HealthCheckResponseObject, error)
	// Liveness probe
	// (GET /healthz)
	LivenessCheck(ctx context.Context, request LivenessCheckRequestObject) (LivenessCheckResponseObject, error)
	// List items
	// (GET /items)
	ListItems(ctx context.Context, request ListItemsRequestObject) (ListItemsResponseObject, error)
	// Create item
	// (POST /items)
	CreateItem(ctx context.Context, request CreateItemRequestObject) (CreateItemResponseObject, error)
	// Delete item
	// (DELETE /items/{id})
	DeleteItem(ctx context.Context, request DeleteItemRequestObject) (DeleteItemResponseObject, error)
	// Get item by ID
	// (GET /items/{id})
	GetItem(ctx context.Context, request GetItemRequestObject) (GetItemResponseObject, error)
	// Update item
	// (PUT /items/{id})
	UpdateItem(ctx context.Context, request UpdateItemRequestObject) (UpdateItemResponseObject, error)
	// Prometheus metrics
	// (GET /metrics)
	GetMetrics(ctx context.Context, request GetMetricsRequestObject) (GetMetricsResponseObject, error)
	// List available actions
	// (GET /rbac/actions)
	ListActions(ctx context.Context, request ListActionsRequestObject) (ListActionsResponseObject, error)
	// List available domains
	// (GET /rbac/domains)
	ListDomains(ctx context.Context, request ListDomainsRequestObject) (ListDomainsResponseObject, error)
	// List all roles
	// (GET /rbac/roles)
	ListRoles(ctx context.Context, request ListRolesRequestObject) (ListRolesResponseObject, error)
	// Create a new role
	// (POST /rbac/roles)
	CreateRole(ctx context.Context, request CreateRoleRequestObject) (CreateRoleResponseObject, error)
	// Delete role
	// (DELETE /rbac/roles/{code})
	DeleteRole(ctx context.Context, request DeleteRoleRequestObject) (DeleteRoleResponseObject, error)
	// Get role by code
	// (GET /rbac/roles/{code})
	GetRole(ctx context.Context, request GetRoleRequestObject) (GetRoleResponseObject, error)
	// Update role permissions
	// (PUT /rbac/roles/{code}/permissions)
	UpdateRolePermissions(ctx context.Context, request UpdateRolePermissionsRequestObject) (UpdateRolePermissionsResponseObject, error)
	// Get user's roles
	// (GET /rbac/users/{id}/roles)
	GetUserRoles(ctx context.Context, request GetUserRolesRequestObject) (GetUserRolesResponseObject, error)
	// Assign role to user
	// (POST /rbac/users/{id}/roles)
	AssignRoleToUser(ctx context.Context, request AssignRoleToUserRequestObject) (AssignRoleToUserResponseObject, error)
	// Remove role from user
	// (DELETE /rbac/users/{id}/roles/{code})
	RemoveRoleFromUser(ctx context.Context, request RemoveRoleFromUserRequestObject) (RemoveRoleFromUserResponseObject, error)
	// Readiness probe
	// (GET /readyz)
	ReadinessCheck(ctx context.Context, request ReadinessCheckRequestObject) (ReadinessCheckResponseObject, error)
	// List all users
	// (GET /users)
	ListUsers(ctx context.Context, request ListUsersRequestObject) (ListUsersResponseObject, error)
	// Get current user
	// (GET /users/me)
	GetCurrentUser(ctx context.Context, request GetCurrentUserRequestObject) (GetCurrentUserResponseObject, error)
	// Update current user
	// (PUT /users/me)
	UpdateCurrentUser(ctx context.Context, request UpdateCurrentUserRequestObject) (UpdateCurrentUserResponseObject, error)
	// List linked OAuth accounts
	// (GET /users/me/identities)
	ListIdentities(ctx context.Context, request ListIdentitiesRequestObject) (ListIdentitiesResponseObject, error)
	// Unlink OAuth account
	// (DELETE /users/me/identities/{provider})
	UnlinkIdentity(ctx context.Context, request UnlinkIdentityRequestObject) (UnlinkIdentityResponseObject, error)
	// Link OAuth account
	// (POST /users/me/identities/{provider})
	LinkIdentity(ctx context.Context, request LinkIdentityRequestObject) (LinkIdentityResponseObject, error)
	// Change password
	// (PUT /users/me/password)
	ChangePassword(ctx context.Context, request ChangePasswordRequestObject) (ChangePasswordResponseObject, error)
	// Set password (OAuth users)
	// (POST /users/me/set-password)
	SetPassword(ctx context.Context, request SetPasswordRequestObject) (SetPasswordResponseObject, error)
	// Delete user
	// (DELETE /users/{id})
	DeleteUser(ctx context.Context, request DeleteUserRequestObject) (DeleteUserResponseObject, error)
	// Get user by ID
	// (GET /users/{id})
	GetUser(ctx context.Context, request GetUserRequestObject) (GetUserResponseObject, error)
}

type StrictHandlerFunc func(ctx *fiber.Ctx, args interface{}) (interface{}, error)

type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
}

// Login operation middleware
func (sh *strictHandler) Login(ctx *fiber.Ctx) error {
	var request LoginRequestObject

	var body LoginJSONRequestBody
	if err := ctx.BodyParser(&body); err != nil {
		return fiber.NewError(fiber.StatusBadRequest, err.Error())
	}
	request.Body = &body

	handler := func(ctx *fiber.Ctx, request interface{}) (interface{}, error) {
		return sh.ssi.Login(ctx.UserContext(), request.(LoginRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "Login")
	}

	response, err := handler(ctx, request)

	if err != nil {
		return fiber.NewError(fiber.StatusBadRequest, err.Error())
	} else if validResponse, ok := response.(LoginResponseObject); ok {
		if err := validResponse.VisitLoginResponse(ctx); err != nil {
			return fiber.NewError(fiber.StatusBadRequest, err.Error())
		}
	} else if response != nil {
		return fmt.Errorf("unexpected response type: %T", response)
	}
	return nil
}

